import requests

BASE_URL = "http://localhost:5173"
LOGIN_ENDPOINT = f"{BASE_URL}/auth/login"
TIMEOUT = 30

def test_user_login_with_valid_credentials():
    url = LOGIN_ENDPOINT
    headers = {
        "Content-Type": "application/json"
    }
    # Example valid credentials for a test user - should match test environment credentials
    payload = {
        "email": "testuser@example.com",
        "password": "ValidPassword123!"
    }
    try:
        response = requests.post(url, json=payload, headers=headers, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Request to {url} failed with exception: {e}"

    assert response.status_code == 200, f"Expected status code 200 but got {response.status_code}"
    try:
        json_data = response.json()
    except ValueError:
        assert False, "Response is not valid JSON"

    # Validate presence of JWT token in the response (commonly in an 'access_token' or 'token' field)
    token = json_data.get("access_token") or json_data.get("token")
    assert token is not None and isinstance(token, str) and len(token) > 0, "JWT token is missing or invalid in response"

test_user_login_with_valid_credentials()
